function removeDuplicates<T>(arr: T[]): T[] {
  return [...new Set(arr)];
}

// For objects, use a key extractor:
function removeDuplicatesBy<T, K>(arr: T[], keyFn: (item: T) => K): T[] {
  const seen = new Set<K>();
  return arr.filter(item => {
    const key = keyFn(item);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

// Usage:
const nums = removeDuplicates([1, 2, 2, 3, 3, 4]); // [1, 2, 3, 4]
const users = removeDuplicatesBy(users, u => u.id);
